const { PrismaClient } = require('@prisma/client');
const p = new PrismaClient();

const codingQuestions = [
  // Gap fills - lessons needing 1-3 more coding questions
  // Lesson 31 needs 1 more
  {lessonId:31,difficulty:"Medium",title:"Star Rating Component",problemStatement:"Build a StarRating component that shows 5 stars. Clicking a star sets the rating. Hovering previews the rating. Support half-stars.",examples:"<StarRating value={3} onChange={setRating} /> shows 3 filled stars.",starterCodeJs:"import { useState } from 'react';\nfunction StarRating({ value=0, onChange, max=5, disabled=false }) {\n  const [hover, setHover] = useState(null);\n  const display = hover ?? value;\n  return (\n    <div className='star-rating' role='radiogroup' aria-label='Rating'>\n      {Array.from({length:max},(_,i)=>i+1).map(star=>(\n        <button key={star} type='button'\n          className={`star ${star<=display?'filled':''}`}\n          onClick={()=>!disabled&&onChange(star)}\n          onMouseEnter={()=>!disabled&&setHover(star)}\n          onMouseLeave={()=>setHover(null)}\n          aria-label={`Rate ${star} of ${max}`}\n          aria-pressed={star===value}>\n          ★\n        </button>\n      ))}\n      <span className='sr-only'>{value} out of {max}</span>\n    </div>\n  );\n}",hints:"hover state shows preview rating on mouse over. ?? (nullish coalescing) falls back to value when hover is null.",solutionExplanation:"Hover state for preview: null means no hover, so display = hover ?? value. Disabled mode prevents click/hover changes."},

  // Lesson 33 needs 2 more
  {lessonId:33,difficulty:"Easy",title:"Counter with useReducer",problemStatement:"Build a counter using useReducer instead of useState. Actions: increment, decrement, reset, set. Min value 0, max value 100.",examples:"dispatch({type:'increment'}) adds 1. dispatch({type:'set', payload:50}) sets to 50.",starterCodeJs:"import { useReducer } from 'react';\nconst counterReducer = (state, action) => {\n  switch(action.type) {\n    case 'increment': return { count: Math.min(state.count+1, state.max) };\n    case 'decrement': return { count: Math.max(state.count-1, state.min) };\n    case 'reset': return { ...state, count: state.initial };\n    case 'set': return { ...state, count: Math.min(Math.max(action.payload, state.min), state.max) };\n    default: return state;\n  }\n};\nfunction Counter({ initial=0, min=0, max=100 }) {\n  const [state, dispatch] = useReducer(counterReducer, { count:initial, initial, min, max });\n  return (\n    <div>\n      <button onClick={()=>dispatch({type:'decrement'})} disabled={state.count<=min}>-</button>\n      <span>{state.count}</span>\n      <button onClick={()=>dispatch({type:'increment'})} disabled={state.count>=max}>+</button>\n      <button onClick={()=>dispatch({type:'reset'})}>Reset</button>\n    </div>\n  );\n}",hints:"Store min/max in reducer state so they're available in reducer without closure. Math.min/max enforce bounds.",solutionExplanation:"useReducer with bounded counter. Store constraints in state so reducer is pure. Disable buttons at bounds."},
  {lessonId:33,difficulty:"Medium",title:"Multi-step Wizard State",problemStatement:"Build a multi-step form wizard state manager using useReducer. Steps: profile, address, payment. Support next, back, and jump to step.",examples:"dispatch({type:'NEXT'}) advances step. dispatch({type:'SET_DATA', step:'profile', data:{...}}) saves data.",starterCodeJs:"import { useReducer } from 'react';\nconst STEPS = ['profile','address','payment','review'];\nconst wizardReducer = (state, action) => {\n  switch(action.type) {\n    case 'NEXT': return { ...state, step: Math.min(state.step+1, STEPS.length-1) };\n    case 'BACK': return { ...state, step: Math.max(state.step-1, 0) };\n    case 'GOTO': return { ...state, step: action.payload };\n    case 'SET_DATA': return { ...state, data: { ...state.data, [action.step]: { ...state.data[action.step], ...action.payload } } };\n    case 'SUBMIT': return { ...state, submitted: true };\n    default: return state;\n  }\n};\nfunction useWizard() {\n  const [state, dispatch] = useReducer(wizardReducer, { step:0, data:{profile:{},address:{},payment:{}}, submitted:false });\n  return { step: STEPS[state.step], stepIndex: state.step, totalSteps: STEPS.length, data: state.data, isFirst: state.step===0, isLast: state.step===STEPS.length-1, submitted: state.submitted, dispatch };\n}",hints:"Store step as index. Data is a nested object keyed by step name. Bounds check on NEXT/BACK.",solutionExplanation:"Wizard state: step index + per-step data. useReducer keeps all mutations predictable. Expose named values (isFirst, isLast) for clean component logic."},

  // Lesson 35 needs 1 more
  {lessonId:35,difficulty:"Hard",title:"Suspense Data Fetching",problemStatement:"Implement a Suspense-compatible data fetching wrapper using the React experimental wrapPromise pattern. Show how Suspense reads data synchronously.",examples:"const resource = fetchUser(1). <Suspense fallback=<Spinner/>><UserProfile resource={resource}/></Suspense>",starterCodeJs:"function wrapPromise(promise) {\n  let status = 'pending', result;\n  const suspender = promise.then(\n    data => { status = 'success'; result = data; },\n    err  => { status = 'error'; result = err; }\n  );\n  return {\n    read() {\n      if (status === 'pending') throw suspender;  // Suspense catches this\n      if (status === 'error') throw result;\n      return result;\n    }\n  };\n}\nfunction fetchUser(id) {\n  return wrapPromise(fetch(`/api/users/${id}`).then(r=>r.json()));\n}\n// Usage (start fetch outside component to avoid waterfall):\nconst userResource = fetchUser(1);\nfunction UserProfile({ resource }) {\n  const user = resource.read(); // throws while pending\n  return <div><h1>{user.name}</h1><p>{user.email}</p></div>;\n}",hints:"Throwing a Promise suspends the component - Suspense catches it. Throwing an Error in 'error' state triggers Error Boundary.",solutionExplanation:"Suspense protocol: throw a Promise while pending, return data when resolved. wrapPromise is the minimal adapter. React Query/SWR use this internally."},

  // Lesson 36 needs 1 more
  {lessonId:36,difficulty:"Medium",title:"Observer Pattern Hook",problemStatement:"Build a useObserver hook that implements the observer pattern. Components can subscribe to any observable value and re-render when it changes.",examples:"const count = useObserver(counterObservable). Changes to counterObservable trigger re-render.",starterCodeJs:"import { useState, useEffect } from 'react';\nfunction createObservable(initialValue) {\n  let value = initialValue;\n  const subscribers = new Set();\n  return {\n    get value() { return value; },\n    set(newValue) {\n      value = newValue;\n      subscribers.forEach(fn => fn(newValue));\n    },\n    subscribe(fn) {\n      subscribers.add(fn);\n      return () => subscribers.delete(fn);\n    }\n  };\n}\nfunction useObserver(observable) {\n  const [value, setValue] = useState(observable.value);\n  useEffect(() => {\n    setValue(observable.value); // sync in case changed before mount\n    return observable.subscribe(setValue);\n  }, [observable]);\n  return value;\n}\nconst count$ = createObservable(0);\nfunction Counter() {\n  const count = useObserver(count$);\n  return <button onClick={() => count$.set(count$.value+1)}>{count}</button>;\n}",hints:"subscribe returns unsubscribe function - use as useEffect cleanup. Sync value on mount in case observable changed between render and effect.",solutionExplanation:"Observable pattern: push-based updates to subscribers. useObserver bridges the observable world to React's state model."},

  // Lesson 37 needs 3 more
  {lessonId:37,difficulty:"Medium",title:"Next.js Image Component",problemStatement:"Build a custom Image component for Next.js that wraps next/image with blur placeholder, error fallback, and aspect ratio container.",examples:"<Image src='/hero.jpg' alt='Hero' aspect={16/9} /> maintains aspect ratio and shows blur placeholder.",starterCodeJs:"'use client';\nimport NextImage from 'next/image';\nimport { useState } from 'react';\nfunction Image({ src, alt, aspect=1, blurDataURL, priority=false, className='' }) {\n  const [error, setError] = useState(false);\n  const paddingTop = `${(1/aspect)*100}%`;\n  if (error) return (\n    <div style={{paddingTop, position:'relative', background:'#f1f5f9'}}>\n      <div style={{position:'absolute',inset:0,display:'flex',alignItems:'center',justifyContent:'center',color:'#94a3b8'}}>\n        Image unavailable\n      </div>\n    </div>\n  );\n  return (\n    <div style={{paddingTop, position:'relative', overflow:'hidden'}} className={className}>\n      <NextImage fill src={src} alt={alt}\n        placeholder={blurDataURL?'blur':'empty'}\n        blurDataURL={blurDataURL}\n        priority={priority}\n        onError={()=>setError(true)}\n        style={{objectFit:'cover'}}\n      />\n    </div>\n  );\n}",hints:"Aspect ratio padding-top trick: (1/ratio)*100%. Next/image with fill needs position:relative parent. Error state shows fallback.",solutionExplanation:"Padding-top % is relative to width, creating responsive aspect ratio box. next/image fill fills the container. onError shows fallback on broken images."},
  {lessonId:37,difficulty:"Hard",title:"Next.js ISR with On-Demand Revalidation",problemStatement:"Build a blog with ISR: pages revalidate every hour. Add an API route that triggers on-demand revalidation when a post is updated.",examples:"POST /api/revalidate?path=/blog/my-post&secret=TOKEN triggers immediate revalidation.",starterCodeJs:"// app/api/revalidate/route.ts\nimport { revalidatePath, revalidateTag } from 'next/cache';\nimport { NextRequest, NextResponse } from 'next/server';\nexport async function POST(request) {\n  const { searchParams } = new URL(request.url);\n  const secret = searchParams.get('secret');\n  if (secret !== process.env.REVALIDATION_SECRET) {\n    return NextResponse.json({ error: 'Invalid secret' }, { status: 401 });\n  }\n  const path = searchParams.get('path');\n  const tag = searchParams.get('tag');\n  try {\n    if (path) revalidatePath(path);\n    if (tag) revalidateTag(tag);\n    return NextResponse.json({ revalidated: true, path, tag, now: Date.now() });\n  } catch (err) {\n    return NextResponse.json({ error: err.message }, { status: 500 });\n  }\n}\n// app/blog/[slug]/page.tsx\nexport const revalidate = 3600; // 1 hour ISR\nasync function BlogPost({ params }) {\n  const post = await fetch(`/api/posts/${params.slug}`, { next: { tags: [`post-${params.slug}`] } }).then(r=>r.json());\n  return <article><h1>{post.title}</h1><p>{post.body}</p></article>;\n}",hints:"revalidateTag invalidates all fetches tagged with that string. Secret token prevents unauthorized revalidation. next:{tags:[]} in fetch enables tag-based invalidation.",solutionExplanation:"ISR: pages built statically, revalidated on interval (revalidate=3600). On-demand: webhook from CMS calls /api/revalidate?tag=post-slug for immediate update."},
  {lessonId:37,difficulty:"Easy",title:"Next.js Environment Variables",problemStatement:"Demonstrate correct use of Next.js environment variables: server-only (no prefix), client-side (NEXT_PUBLIC_), and runtime config.",examples:"process.env.DATABASE_URL server only. process.env.NEXT_PUBLIC_API_URL available in browser.",starterCodeJs:"// .env.local\n// DATABASE_URL=mysql://...  (server only - never in bundle)\n// JWT_SECRET=secret         (server only)\n// NEXT_PUBLIC_API_URL=https://api.example.com  (in browser bundle)\n// NEXT_PUBLIC_APP_NAME=MyApp  (in browser bundle)\n// Server Component - can use any env var:\nasync function ServerPage() {\n  const db = await connectDB(process.env.DATABASE_URL);\n  const data = await db.query('SELECT 1');\n  return <ClientComponent apiUrl={process.env.NEXT_PUBLIC_API_URL} />;\n}\n// Client Component - only NEXT_PUBLIC_ vars:\n'use client';\nfunction ClientComponent({ apiUrl }) {\n  // process.env.NEXT_PUBLIC_API_URL also works in client components\n  // process.env.DATABASE_URL is undefined in client (intentionally)\n  const [data, setData] = useState(null);\n  useEffect(() => { fetch(`${apiUrl}/data`).then(r=>r.json()).then(setData); }, [apiUrl]);\n  return <div>{JSON.stringify(data)}</div>;\n}",hints:"NEXT_PUBLIC_ prefix embeds value in JS bundle at build time. Server env vars are never sent to browser. Pass server values to client via props.",solutionExplanation:"NEXT_PUBLIC_ vars are inlined at build time - they're in the JS bundle. Server-only vars (DATABASE_URL) are available only in Server Components and API routes."},

  // Lesson 39 needs 1 more
  {lessonId:39,difficulty:"Hard",title:"Streaming File Upload",problemStatement:"Build a Node.js endpoint that streams large file uploads directly to disk without buffering the entire file in memory.",examples:"POST /upload streams multipart body, writes each chunk to disk. Handles 10GB files efficiently.",starterCodeJs:"const http = require('http');\nconst fs = require('fs');\nconst path = require('path');\nconst { pipeline } = require('stream/promises');\nconst Busboy = require('busboy');\nconst server = http.createServer(async (req, res) => {\n  if (req.method !== 'POST' || req.url !== '/upload') { res.end('Not Found'); return; }\n  const busboy = Busboy({ headers: req.headers, limits: { fileSize: 10 * 1024**3 } });\n  const files = [];\n  busboy.on('file', (name, stream, info) => {\n    const { filename, mimeType } = info;\n    const safeName = path.basename(filename).replace(/[^a-zA-Z0-9.-]/g,'_');\n    const dest = path.join('uploads', Date.now() + '-' + safeName);\n    files.push({ name: safeName, path: dest, type: mimeType });\n    pipeline(stream, fs.createWriteStream(dest)).catch(console.error);\n  });\n  busboy.on('finish', () => { res.writeHead(200,{'Content-Type':'application/json'}); res.end(JSON.stringify({files})); });\n  busboy.on('error', err => { res.writeHead(500); res.end(err.message); });\n  req.pipe(busboy);\n});\nserver.listen(3000);",hints:"Busboy parses multipart streams. Pipe file stream directly to fs.createWriteStream - no buffering. Sanitize filename to prevent path traversal.",solutionExplanation:"Stream directly to disk: file data never accumulates in memory. Busboy parses multipart headers and yields file streams. pipeline handles cleanup."},

  // Lesson 40 needs 2 more
  {lessonId:40,difficulty:"Medium",title:"Database Health Monitor",problemStatement:"Build a database health monitor that periodically checks connection, query time, and table sizes. Alerts when thresholds exceeded.",examples:"monitor.start(30000) checks every 30s. Emits 'alert' when query >100ms or connection fails.",starterCodeJs:"const { EventEmitter } = require('events');\nclass DBHealthMonitor extends EventEmitter {\n  constructor(db, options = {}) {\n    super();\n    this._db = db;\n    this._interval = options.interval || 30000;\n    this._thresholds = { queryMs: options.queryMs || 100, ...options.thresholds };\n    this._timer = null;\n  }\n  start() {\n    this._timer = setInterval(() => this.check(), this._interval);\n    this.check(); return this;\n  }\n  stop() { clearInterval(this._timer); return this; }\n  async check() {\n    const results = {};\n    try {\n      const t = Date.now();\n      await this._db.get('SELECT 1');\n      results.queryMs = Date.now() - t;\n      results.connected = true;\n      if (results.queryMs > this._thresholds.queryMs) {\n        this.emit('alert', { type:'slow_query', queryMs: results.queryMs, threshold: this._thresholds.queryMs });\n      }\n    } catch(err) {\n      results.connected = false;\n      this.emit('alert', { type:'connection_error', error: err.message });\n    }\n    results.memory = process.memoryUsage();\n    this.emit('check', results);\n    return results;\n  }\n}",hints:"EventEmitter for alerts enables loose coupling. setInterval for periodic checks. clearInterval on stop prevents memory leaks.",solutionExplanation:"Health monitor emits events rather than logging directly. Consumers decide what to do with alerts. setInterval/clearInterval for lifecycle management."},
  {lessonId:40,difficulty:"Hard",title:"Batch Database Operations",problemStatement:"Build a batch processor that groups individual DB writes into bulk operations. Reduces N individual inserts into 1 bulk insert.",examples:"batcher.add({name:'Alice'}). After 100 items or 50ms, flush inserts all at once.",starterCodeJs:"class BatchProcessor {\n  constructor(db, options = {}) {\n    this._db = db;\n    this._table = options.table || 'items';\n    this._maxSize = options.maxSize || 100;\n    this._maxWaitMs = options.maxWaitMs || 50;\n    this._queue = [];\n    this._resolvers = [];\n    this._timer = null;\n  }\n  add(item) {\n    return new Promise((resolve, reject) => {\n      this._queue.push(item);\n      this._resolvers.push({ resolve, reject });\n      if (this._queue.length >= this._maxSize) {\n        this._flush();\n      } else if (!this._timer) {\n        this._timer = setTimeout(() => this._flush(), this._maxWaitMs);\n      }\n    });\n  }\n  async _flush() {\n    clearTimeout(this._timer);\n    this._timer = null;\n    const items = this._queue.splice(0);\n    const resolvers = this._resolvers.splice(0);\n    if (!items.length) return;\n    try {\n      const placeholders = items.map(()=>'('+Object.keys(items[0]).map(()=>'?').join(',')+')').join(',');\n      const values = items.flatMap(i=>Object.values(i));\n      const result = await this._db.run(`INSERT INTO ${this._table} (${Object.keys(items[0]).join(',')}) VALUES ${placeholders}`, values);\n      resolvers.forEach(r => r.resolve(result));\n    } catch(err) {\n      resolvers.forEach(r => r.reject(err));\n    }\n  }\n}",hints:"Flush when queue hits maxSize OR after maxWaitMs timeout. Clear timer when flushing by size. Each add() returns a Promise resolved after bulk insert.",solutionExplanation:"Batching reduces DB round trips. Auto-flush on size (max) or time (max wait). Each caller gets a Promise that resolves when their batch is committed."},

  // Lesson 46 needs 1 more
  {lessonId:46,difficulty:"Hard",title:"Request Replay Middleware",problemStatement:"Build middleware that captures failed requests and allows replaying them. Useful for debugging - replay a production request in development.",examples:"REPLAY header triggers replay mode. Stores last N requests. POST /debug/replay/{id} replays stored request.",starterCodeJs:"const requestStore = [];\nconst MAX_STORED = 100;\nfunction captureRequests(req, res, next) {\n  const chunks = [];\n  req.on('data', c => chunks.push(c));\n  req.on('end', () => {\n    const body = Buffer.concat(chunks);\n    const stored = {\n      id: Date.now(),\n      method: req.method,\n      url: req.url,\n      headers: { ...req.headers },\n      body: body.toString(),\n      timestamp: new Date().toISOString()\n    };\n    requestStore.unshift(stored);\n    if (requestStore.length > MAX_STORED) requestStore.pop();\n    req._rawBody = body;\n    // Re-emit the body so body-parser can read it\n    const { Readable } = require('stream');\n    const readable = new Readable();\n    readable.push(body);\n    readable.push(null);\n    Object.assign(req, readable);\n    next();\n  });\n}\nfunction replayEndpoint(app) {\n  app.get('/debug/requests', (req,res) => res.json(requestStore.map(({body,...r})=>r)));\n  app.post('/debug/replay/:id', (req,res) => {\n    const stored = requestStore.find(r=>r.id===parseInt(req.params.id));\n    if (!stored) return res.status(404).json({error:'Not found'});\n    res.json({ replaying: true, request: stored });\n  });\n}",hints:"Buffer body chunks to capture raw request. Re-emit body for downstream parsers. Store in ring buffer (splice when over limit).",solutionExplanation:"Request capture: buffer data chunks, store metadata. Ring buffer prevents memory growth. Re-emit body because streams can only be read once."},

  // Lesson 47 needs 2 more
  {lessonId:47,difficulty:"Hard",title:"OpenAPI Spec Generator",problemStatement:"Build a function that generates a basic OpenAPI 3.0 spec from your Express routes. Output JSON spec with paths, methods, and basic schemas.",examples:"generateSpec(app) -> OpenAPI 3.0 JSON with all registered routes as paths.",starterCodeJs:"function generateSpec(routeDefinitions, info = {}) {\n  const paths = {};\n  for (const route of routeDefinitions) {\n    const path = route.path.replace(/:([a-z]+)/g, '{$1}'); // /users/:id -> /users/{id}\n    if (!paths[path]) paths[path] = {};\n    const method = route.method.toLowerCase();\n    paths[path][method] = {\n      summary: route.description || '',\n      tags: route.tags || [route.path.split('/')[1]],\n      parameters: (route.path.match(/:([a-z]+)/g)||[]).map(p => ({\n        name: p.slice(1), in:'path', required:true, schema:{type:'string'}\n      })),\n      responses: {\n        '200': { description: 'Success' },\n        '400': { description: 'Bad Request' },\n        '404': { description: 'Not Found' },\n        '500': { description: 'Server Error' }\n      }\n    };\n    if (['post','put','patch'].includes(method)) {\n      paths[path][method].requestBody = { required:true, content: { 'application/json': { schema: { type:'object' } } } };\n    }\n  }\n  return { openapi:'3.0.0', info: { title:'API', version:'1.0.0', ...info }, paths };\n}",hints:"Convert Express :param to OpenAPI {param}. Extract path params from route pattern with regex. Group by path, then by method.",solutionExplanation:"OpenAPI spec generation: paths object keyed by path, then method. :param -> {param} conversion. Real tools like swagger-jsdoc parse JSDoc comments."},
  {lessonId:47,difficulty:"Medium",title:"GraphQL vs REST Comparison",problemStatement:"Implement the same data fetching in both REST and GraphQL style. Show how GraphQL solves over-fetching and under-fetching.",examples:"REST: 3 requests for user+posts+comments. GraphQL: 1 request with nested query.",starterCodeJs:"// REST approach - over-fetching and N+1\nasync function getProfileREST(userId) {\n  const user = await fetch(`/api/users/${userId}`).then(r=>r.json());\n  const posts = await fetch(`/api/users/${userId}/posts`).then(r=>r.json());\n  const comments = await Promise.all(posts.slice(0,3).map(p => fetch(`/api/posts/${p.id}/comments`).then(r=>r.json())));\n  return { user, posts: posts.slice(0,3), comments }; // 1 + 1 + 3 = 5 requests!\n}\n// GraphQL approach - exact data, one request\nconst PROFILE_QUERY = `\n  query GetProfile($userId: ID!) {\n    user(id: $userId) {\n      name email avatar\n      posts(first: 3) {\n        title createdAt\n        comments(first: 5) { body author { name } }\n      }\n    }\n  }\n`;\nasync function getProfileGraphQL(userId) {\n  const res = await fetch('/graphql', {\n    method:'POST', headers:{'Content-Type':'application/json'},\n    body: JSON.stringify({ query: PROFILE_QUERY, variables: { userId } })\n  });\n  return res.json();\n}",hints:"REST: multiple round trips, over-fetching (all user fields). GraphQL: one request, exactly requested fields. Trade-off: GraphQL complexity vs REST simplicity.",solutionExplanation:"REST: simple but multiple requests for related data. GraphQL: declare data needs, server resolves optimally. N+1 in REST vs DataLoader batching in GraphQL."},

  // Lesson 48 needs 5 more
  {lessonId:48,difficulty:"Medium",title:"Express with TypeScript",problemStatement:"Set up an Express app with TypeScript. Define typed request interfaces, custom Request type with user, and typed route handlers.",examples:"TypedRequest<{id:string}, UserBody> gives typed req.params and req.body.",starterCodeJs:"import express, { Request, Response, NextFunction, Router } from 'express';\ninterface AuthUser { id: number; email: string; role: string; }\ndeclare global { namespace Express { interface Request { user?: AuthUser; } } }\ntype TypedRequest<P={}, B={}, Q={}> = Request<P, any, B, Q>;\ninterface UserParams { id: string; }\ninterface CreateUserBody { name: string; email: string; }\nconst router = Router();\nrouter.get('/:id', async (req: TypedRequest<UserParams>, res: Response) => {\n  const userId = parseInt(req.params.id);\n  if (isNaN(userId)) return res.status(400).json({ error: 'Invalid ID' });\n  const user = await db.user.findUnique({ where: { id: userId } });\n  if (!user) return res.status(404).json({ error: 'Not found' });\n  res.json(user);\n});\nrouter.post('/', async (req: TypedRequest<{}, CreateUserBody>, res: Response) => {\n  const { name, email } = req.body;\n  const user = await db.user.create({ data: { name, email } });\n  res.status(201).json(user);\n});",hints:"Augment Express.Request namespace to add user property. Generic TypedRequest makes params/body type-safe. parseInt+isNaN validates numeric route params.",solutionExplanation:"TypeScript augmentation: extend Express.Request namespace globally. Generic request type provides per-route body/param types."},
  {lessonId:48,difficulty:"Medium",title:"Express Dependency Injection",problemStatement:"Refactor an Express app to use dependency injection. Pass db, mailer, etc. as constructor dependencies to avoid module-level singletons.",examples:"createApp({db, mailer, cache}) returns Express app. Easy to test with mocks.",starterCodeJs:"function createRouter({ db, mailer, cache }) {\n  const router = require('express').Router();\n  router.get('/users', async (req, res) => {\n    const cached = await cache.get('users');\n    if (cached) return res.json(JSON.parse(cached));\n    const users = await db.user.findMany();\n    await cache.set('users', JSON.stringify(users), 60);\n    res.json(users);\n  });\n  router.post('/users', async (req, res) => {\n    const user = await db.user.create({ data: req.body });\n    await mailer.send({ to: user.email, subject: 'Welcome!', body: `Hi ${user.name}` });\n    res.status(201).json(user);\n  });\n  return router;\n}\nfunction createApp(deps) {\n  const app = require('express')();\n  app.use(require('express').json());\n  app.use('/api/users', createRouter(deps));\n  return app;\n}\nmodule.exports = { createApp };\n// test: const app = createApp({ db: mockDb, mailer: mockMailer, cache: mockCache });",hints:"Factory functions instead of singletons. Pass dependencies as params. Tests can inject mocks without require() mocking.",solutionExplanation:"DI without framework: factory functions accept deps as params. Test isolation: pass mock implementations. No need for require() monkey-patching in tests."},
  {lessonId:48,difficulty:"Hard",title:"Express Performance Profiler",problemStatement:"Build middleware that profiles request handling: time each middleware, identify bottlenecks, and report per-route performance metrics.",examples:"After request: {route:'/api/users', total:45ms, middleware:[{name:'auth',ms:2},{name:'db',ms:40}]}",starterCodeJs:"const metrics = new Map();\nfunction profile(name) {\n  return (req, res, next) => {\n    if (!req._profile) req._profile = { route: req.path, middleware: [], start: Date.now() };\n    const t = Date.now();\n    const done = () => req._profile.middleware.push({ name, ms: Date.now()-t });\n    const origNext = next;\n    next = (...args) => { done(); origNext(...args); };\n    next();\n  };\n}\nfunction profileReport(req, res, next) {\n  const start = Date.now();\n  res.on('finish', () => {\n    if (!req._profile) return;\n    const report = { ...req._profile, total: Date.now()-start, status: res.statusCode };\n    const key = `${req.method} ${req.route?.path || req.path}`;\n    if (!metrics.has(key)) metrics.set(key, { count:0, totalMs:0, p95:[] });\n    const m = metrics.get(key);\n    m.count++;\n    m.totalMs += report.total;\n    m.p95.push(report.total);\n    if (m.p95.length > 1000) m.p95.shift();\n    console.log('[PERF]', JSON.stringify(report));\n  });\n  next();\n}\nfunction getMetrics() {\n  const result = {};\n  for (const [k,v] of metrics) {\n    const sorted = [...v.p95].sort((a,b)=>a-b);\n    result[k] = { count:v.count, avgMs:(v.totalMs/v.count).toFixed(1), p95Ms:sorted[Math.floor(sorted.length*0.95)]||0 };\n  }\n  return result;\n}",hints:"Track per-middleware timing by wrapping next(). res.on('finish') fires after response sent. Rolling p95 window (last 1000 requests).",solutionExplanation:"Performance profiling: wrap each middleware's next() to measure time. Aggregate metrics per route. P95 (95th percentile) is a standard latency metric."},
  {lessonId:48,difficulty:"Easy",title:"Express Static Site Generator",problemStatement:"Build an Express app that serves a static site from markdown files. Reads .md files from a directory, converts to HTML, and serves them.",examples:"GET /about -> reads pages/about.md, converts to HTML, serves with layout.",starterCodeJs:"const express = require('express');\nconst fs = require('fs').promises;\nconst path = require('path');\nconst { marked } = require('marked');\nconst app = express();\nconst PAGES_DIR = path.join(__dirname, 'pages');\nfunction layout(title, content) {\n  return `<!DOCTYPE html><html><head><title>${title}</title><link rel='stylesheet' href='/styles.css'></head><body><nav><a href='/'>Home</a> <a href='/about'>About</a></nav><main>${content}</main></body></html>`;\n}\nasync function servePage(req, res, next) {\n  const slug = req.params.slug || 'index';\n  const filePath = path.join(PAGES_DIR, `${slug}.md`);\n  try {\n    const md = await fs.readFile(filePath, 'utf8');\n    const firstLine = md.split('\\n')[0].replace(/^#+\\s*/, '');\n    const html = marked(md);\n    res.send(layout(firstLine, html));\n  } catch (e) {\n    if (e.code === 'ENOENT') next(); else next(e);\n  }\n}\napp.use(express.static('public'));\napp.get('/', servePage);\napp.get('/:slug', servePage);",hints:"path.join prevents directory traversal. ENOENT (file not found) -> pass to 404 handler. marked() converts markdown to HTML.",solutionExplanation:"Static site from markdown: read file, convert with marked, wrap in layout. ENOENT means page not found -> call next() for 404 handling."},
  {lessonId:48,difficulty:"Hard",title:"API Gateway Pattern",problemStatement:"Build a simple API gateway in Express that routes requests to upstream services, adds auth headers, and aggregates responses.",examples:"GET /gateway/users -> proxies to user-service:3001. Adds X-Auth-Token header.",starterCodeJs:"const express = require('express');\nconst { createProxyMiddleware } = require('http-proxy-middleware');\nconst app = express();\nconst services = {\n  users: 'http://user-service:3001',\n  posts: 'http://post-service:3002',\n  auth: 'http://auth-service:3003'\n};\nfunction addServiceAuth(req, res, proxyReq) {\n  proxyReq.setHeader('X-Gateway-Service', 'api-gateway');\n  proxyReq.setHeader('X-Request-ID', req.id || Math.random().toString(36).slice(2));\n  if (req.user) proxyReq.setHeader('X-User-ID', String(req.user.id));\n}\nfor (const [name, target] of Object.entries(services)) {\n  app.use(`/gateway/${name}`, createProxyMiddleware({\n    target, changeOrigin: true,\n    pathRewrite: { [`^/gateway/${name}`]: '' },\n    on: { proxyReq: addServiceAuth }\n  }));\n}\n// Aggregation endpoint\napp.get('/gateway/dashboard', async (req, res) => {\n  const [user, posts] = await Promise.all([\n    fetch(`${services.users}/users/${req.query.userId}`).then(r=>r.json()),\n    fetch(`${services.posts}/posts?userId=${req.query.userId}`).then(r=>r.json())\n  ]);\n  res.json({ user, posts });\n});",hints:"http-proxy-middleware handles request forwarding. proxyReq event adds headers before forwarding. Aggregation endpoint calls multiple services in parallel.",solutionExplanation:"API Gateway: single entry point, routes to services. pathRewrite strips gateway prefix. Aggregation combines multiple service calls into one response."},

  // Lessons 49-50 more coding
  {lessonId:49,difficulty:"Hard",title:"Database Migration with Rollback",problemStatement:"Write a complete database migration system with up/down support. Create users table migration, add index migration, add columns migration.",examples:"migrations/001_create_users.sql: -- UP section then -- DOWN section.",starterCodeJs:"// 001_create_users.sql structure:\nconst migration001 = {\n  name: '001_create_users',\n  up: `\n    CREATE TABLE users (\n      id INTEGER PRIMARY KEY AUTOINCREMENT,\n      name TEXT NOT NULL,\n      email TEXT UNIQUE NOT NULL,\n      password_hash TEXT,\n      role TEXT DEFAULT 'user' CHECK(role IN ('user','admin','moderator')),\n      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP\n    );\n    CREATE INDEX idx_users_email ON users(email);\n    CREATE INDEX idx_users_role ON users(role);\n  `,\n  down: `\n    DROP INDEX IF EXISTS idx_users_role;\n    DROP INDEX IF EXISTS idx_users_email;\n    DROP TABLE IF EXISTS users;\n  `\n};\nconst migration002 = {\n  name: '002_add_user_avatar',\n  up: `ALTER TABLE users ADD COLUMN avatar TEXT;\n       ALTER TABLE users ADD COLUMN bio TEXT;`,\n  down: `-- SQLite doesn't support DROP COLUMN easily\n         -- Create new table without columns, copy data, rename\n         CREATE TABLE users_new AS SELECT id,name,email,password_hash,role,created_at,updated_at FROM users;\n         DROP TABLE users;\n         ALTER TABLE users_new RENAME TO users;`\n};",hints:"Each migration has up (apply) and down (rollback) SQL. DOWN for ALTER TABLE in SQLite requires table recreation. Include both indexes and table.",solutionExplanation:"Migration files: deterministic, ordered, reversible. SQLite ALTER TABLE limitations: DROP COLUMN not supported until SQLite 3.35. Workaround: recreate table."},
  {lessonId:50,difficulty:"Medium",title:"Time Series Data Store",problemStatement:"Build an in-memory time series store for metrics. Support: record(metric, value), query(metric, from, to), aggregate(metric, window, fn).",examples:"ts.record('cpu', 85). ts.query('cpu', Date.now()-60000, Date.now()). ts.aggregate('cpu', 5000, 'avg').",starterCodeJs:"class TimeSeriesStore {\n  constructor({ maxPoints = 10000 } = {}) {\n    this._series = new Map();\n    this._maxPoints = maxPoints;\n  }\n  record(metric, value, timestamp = Date.now()) {\n    if (!this._series.has(metric)) this._series.set(metric, []);\n    const series = this._series.get(metric);\n    series.push({ t: timestamp, v: value });\n    if (series.length > this._maxPoints) series.shift();\n  }\n  query(metric, from, to = Date.now()) {\n    return (this._series.get(metric) || []).filter(p => p.t >= from && p.t <= to);\n  }\n  aggregate(metric, windowMs, fn = 'avg', from, to = Date.now()) {\n    const points = this.query(metric, from || to - windowMs * 100, to);\n    const buckets = new Map();\n    points.forEach(p => {\n      const bucket = Math.floor(p.t / windowMs) * windowMs;\n      if (!buckets.has(bucket)) buckets.set(bucket, []);\n      buckets.get(bucket).push(p.v);\n    });\n    const agg = { avg: arr => arr.reduce((a,b)=>a+b,0)/arr.length, max: arr => Math.max(...arr), min: arr => Math.min(...arr), count: arr => arr.length };\n    return [...buckets.entries()].sort((a,b)=>a[0]-b[0]).map(([t,vals]) => ({ t, v: (agg[fn]||agg.avg)(vals) }));\n  }\n  metrics() { return [...this._series.keys()]; }\n}",hints:"Time-bucket aggregation: floor(timestamp/windowMs)*windowMs groups into windows. Circular buffer (shift oldest when over maxPoints).",solutionExplanation:"Time series: ordered by timestamp, query by range. Bucketing: floor to nearest window boundary groups points. Aggregate functions computed per bucket."},
  {lessonId:50,difficulty:"Hard",title:"Distributed Counter with Conflict Resolution",problemStatement:"Build a CRDT-based counter that can be incremented on multiple nodes and merged without conflicts. Each node tracks its own increments.",examples:"node1.increment(), node2.increment() merge to count=2 even without coordination.",starterCodeJs:"class GCounter {\n  constructor(nodeId) {\n    this._nodeId = nodeId;\n    this._counts = { [nodeId]: 0 };\n  }\n  increment(amount = 1) {\n    this._counts[this._nodeId] = (this._counts[this._nodeId] || 0) + amount;\n    return this;\n  }\n  value() { return Object.values(this._counts).reduce((a,b) => a+b, 0); }\n  merge(other) {\n    // Take max of each node's count (CRDT merge = element-wise max)\n    const merged = { ...this._counts };\n    for (const [nodeId, count] of Object.entries(other._counts)) {\n      merged[nodeId] = Math.max(merged[nodeId] || 0, count);\n    }\n    const result = new GCounter(this._nodeId);\n    result._counts = merged;\n    return result;\n  }\n  state() { return { ...this._counts }; }\n  static fromState(nodeId, state) {\n    const c = new GCounter(nodeId);\n    c._counts = { ...state };\n    return c;\n  }\n}\nconst n1 = new GCounter('node1');\nconst n2 = new GCounter('node2');\nn1.increment(); n1.increment();\nn2.increment();\nconst merged = n1.merge(n2);\nconsole.log(merged.value()); // 3",hints:"G-Counter CRDT: each node owns its count, merge takes element-wise max. Total = sum of all nodes. No coordination needed.",solutionExplanation:"CRDT G-Counter: grow-only counter. Each node increments only its slot. Merge = max per node (idempotent). Ensures eventual consistency without coordination."},

  // Lessons 51-53 coding (ORM, Database Design, Performance)
  // Lesson 51 needs 10 coding questions
  {lessonId:51,difficulty:"Easy",title:"Prisma Basic CRUD",problemStatement:"Write Prisma operations for a User model: create, findUnique, findMany with filters, update, delete, and count.",examples:"p.user.create({data:{name,email}}). p.user.findMany({where:{role:'admin'}}).",starterCodeJs:"const { PrismaClient } = require('@prisma/client');\nconst p = new PrismaClient();\nasync function userCRUD() {\n  // Create\n  const user = await p.user.create({ data: { name: 'Alice', email: 'alice@example.com', role: 'user' } });\n  // Find by unique field\n  const found = await p.user.findUnique({ where: { email: 'alice@example.com' } });\n  // Find many with filter\n  const admins = await p.user.findMany({ where: { role: 'admin' }, orderBy: { name: 'asc' }, take: 10 });\n  // Update\n  const updated = await p.user.update({ where: { id: user.id }, data: { name: 'Alice Smith' } });\n  // Upsert (create or update)\n  const upserted = await p.user.upsert({ where: { email: 'bob@example.com' }, create: { name: 'Bob', email: 'bob@example.com' }, update: { name: 'Bob Updated' } });\n  // Delete\n  await p.user.delete({ where: { id: user.id } });\n  // Count\n  const total = await p.user.count({ where: { role: 'user' } });\n  return { total, admins: admins.length };\n}",hints:"findUnique requires a unique/ID field. findFirst for non-unique. upsert = create if not exists, update if exists. count() with where clause.",solutionExplanation:"Prisma CRUD: type-safe operations. findUnique on unique fields only. upsert avoids race condition of check-then-create. count() for pagination total."},
  {lessonId:51,difficulty:"Medium",title:"Prisma Relations Query",problemStatement:"Write Prisma queries that load related data: user with posts, posts with author and comments, nested create (user + posts in one query).",examples:"p.user.findUnique({where:{id},include:{posts:{include:{comments:true}}}}).",starterCodeJs:"async function relationQueries(p) {\n  // User with all posts\n  const userWithPosts = await p.user.findUnique({\n    where: { id: 1 },\n    include: { posts: { orderBy: { createdAt: 'desc' }, take: 10 } }\n  });\n  // Post with author and comments count\n  const postWithDetails = await p.post.findUnique({\n    where: { id: 1 },\n    include: { author: { select: { id:true, name:true, avatar:true } }, _count: { select: { comments:true, likes:true } } }\n  });\n  // Nested create: user + first post in one transaction\n  const userWithFirstPost = await p.user.create({\n    data: { name: 'Alice', email: 'alice@test.com', posts: { create: [{ title: 'My First Post', body: 'Hello world!' }] } },\n    include: { posts: true }\n  });\n  // Select only specific fields\n  const emailList = await p.user.findMany({ select: { id: true, email: true }, where: { role: 'user' } });\n  return { userWithPosts, postWithDetails, userWithFirstPost, emailList };\n}",hints:"include loads related records. select picks specific fields. _count counts related records. Nested create creates related records atomically.",solutionExplanation:"Prisma relations: include vs select (mutually exclusive at same level). _count for relationship counts. Nested create wraps in implicit transaction."},
  {lessonId:51,difficulty:"Medium",title:"Prisma Transaction",problemStatement:"Use Prisma transactions for: transferring credits between users, creating post with required tags, and batch operations.",examples:"p.$transaction([p.user.update({dec credits}), p.user.update({inc credits})])",starterCodeJs:"async function transactions(p) {\n  // Sequential transaction (interactive)\n  await p.$transaction(async (tx) => {\n    const sender = await tx.user.findUnique({ where: { id: 1 } });\n    if (!sender || sender.credits < 10) throw new Error('Insufficient credits');\n    await tx.user.update({ where: { id: 1 }, data: { credits: { decrement: 10 } } });\n    await tx.user.update({ where: { id: 2 }, data: { credits: { increment: 10 } } });\n    await tx.transaction.create({ data: { fromId: 1, toId: 2, amount: 10 } });\n  });\n  // Batch transaction (parallel queries in one tx)\n  const [users, posts, comments] = await p.$transaction([\n    p.user.findMany({ take: 10 }),\n    p.post.findMany({ take: 10 }),\n    p.comment.findMany({ take: 10 })\n  ]);\n  // Upsert many\n  await p.$transaction(\n    ['tag1','tag2','tag3'].map(name => p.tag.upsert({ where: { name }, create: { name }, update: {} }))\n  );\n  return { users, posts, comments };\n}",hints:"Interactive tx: async callback with tx client. Batch tx: array of operations. throw inside transaction triggers automatic rollback.",solutionExplanation:"Prisma $transaction: interactive (callback) for dependent operations. Batch (array) for independent parallel operations. Throw triggers rollback in interactive mode."},
  {lessonId:51,difficulty:"Hard",title:"Prisma Middleware",problemStatement:"Add Prisma middleware for: soft delete (mark deleted instead of removing), timestamps (auto updated_at), and audit logging.",examples:"p.user.delete() -> sets deletedAt=now. p.user.findMany() -> auto excludes soft-deleted.",starterCodeJs:"function addPrismaMiddleware(p) {\n  // Soft delete middleware\n  p.$use(async (params, next) => {\n    if (params.model === 'User') {\n      if (params.action === 'delete') {\n        params.action = 'update';\n        params.args.data = { deletedAt: new Date() };\n      }\n      if (params.action === 'findMany' || params.action === 'findFirst') {\n        params.args.where = { ...params.args.where, deletedAt: null };\n      }\n    }\n    return next(params);\n  });\n  // Auto updated_at\n  p.$use(async (params, next) => {\n    if (['update','updateMany','upsert'].includes(params.action)) {\n      if (params.args.data) params.args.data.updatedAt = new Date();\n    }\n    return next(params);\n  });\n  // Audit log\n  p.$use(async (params, next) => {\n    const result = await next(params);\n    if (['create','update','delete'].includes(params.action) && params.model) {\n      console.log(`[AUDIT] ${params.model}.${params.action}`, { args: params.args });\n    }\n    return result;\n  });\n}",hints:"Prisma middleware intercepts all queries. Modify params to change action or args. Call next(params) to continue. Chain multiple middleware.",solutionExplanation:"Middleware intercepts DB operations. Soft delete: convert delete to update+deletedAt. Auto-filter: add deletedAt:null to all finds. Middleware compose in order."},
  {lessonId:51,difficulty:"Easy",title:"Prisma Select and Omit",problemStatement:"Demonstrate Prisma's select and omit to return only needed fields. Show why you should omit password_hash from user queries.",examples:"findUsers() returns name,email but not password_hash. select:{} picks fields, omit:{} excludes them.",starterCodeJs:"async function safeUserQueries(p) {\n  // Select only needed fields (exclude sensitive data)\n  const publicUser = await p.user.findUnique({\n    where: { id: 1 },\n    select: { id: true, name: true, email: true, avatar: true, role: true, createdAt: true }\n  });\n  // Omit specific fields (Prisma 5.13+)\n  const userWithoutPassword = await p.user.findMany({\n    omit: { passwordHash: true },\n    take: 10\n  });\n  // Custom type-safe user projection\n  const selectPublicUser = { id:true, name:true, email:true, avatar:true } as const;\n  type PublicUser = Prisma.UserGetPayload<{select: typeof selectPublicUser}>;\n  const users: PublicUser[] = await p.user.findMany({ select: selectPublicUser });\n  // Nested select\n  const postWithAuthor = await p.post.findMany({\n    select: { id:true, title:true, author: { select: { name:true, avatar:true } } }\n  });\n  return { publicUser, userWithoutPassword, users, postWithAuthor };\n}",hints:"Never return passwordHash to client. select and include are mutually exclusive at the same level. omit is simpler when excluding just a few fields.",solutionExplanation:"select reduces payload and prevents accidental sensitive field exposure. Always exclude passwordHash, tokens from public API responses."},
  {lessonId:51,difficulty:"Hard",title:"Prisma Raw Queries",problemStatement:"Use Prisma raw queries for complex SQL that the ORM cannot express: window functions, CTEs, custom aggregations.",examples:"p.$queryRaw for SELECT. p.$executeRaw for INSERT/UPDATE/DELETE. Sql template tag for safety.",starterCodeJs:"const { Prisma } = require('@prisma/client');\nasync function rawQueries(p) {\n  // Safe raw query with tagged template (Prisma.sql)\n  const userId = 1;\n  const user = await p.$queryRaw(Prisma.sql`SELECT id, name FROM users WHERE id = ${userId}`);\n  // Window function (not available in Prisma ORM)\n  const ranked = await p.$queryRaw`\n    SELECT\n      id, name, email,\n      COUNT(posts.id) as post_count,\n      RANK() OVER (ORDER BY COUNT(posts.id) DESC) as rank\n    FROM users\n    LEFT JOIN posts ON posts.author_id = users.id\n    GROUP BY users.id\n    ORDER BY rank\n    LIMIT 10\n  `;\n  // CTE (Common Table Expression)\n  const categoryStats = await p.$queryRaw`\n    WITH post_stats AS (\n      SELECT author_id, COUNT(*) as count FROM posts GROUP BY author_id\n    )\n    SELECT u.name, ps.count\n    FROM users u JOIN post_stats ps ON ps.author_id = u.id\n    WHERE ps.count > 5\n  `;\n  // Execute (non-select)\n  const { count } = await p.$executeRaw`UPDATE users SET last_active = NOW() WHERE id = ${userId}`;\n  return { user, ranked, categoryStats, count };\n}",hints:"Always use Prisma.sql`` or tagged template for user input - prevents SQL injection. $queryRaw returns typed results. $executeRaw returns affected row count.",solutionExplanation:"Raw queries when ORM can't express: window functions, CTEs, complex aggregations. Prisma.sql`` ensures parameterized queries. Returns typed results."},
  {lessonId:51,difficulty:"Medium",title:"Prisma Seed Script",problemStatement:"Write a complete Prisma seed script that creates realistic test data with proper relationships. Users, posts, comments, tags.",examples:"seed() creates 10 users, 3 posts per user, 5 comments per post, shared tags.",starterCodeJs:"const { PrismaClient } = require('@prisma/client');\nconst p = new PrismaClient();\nasync function seed() {\n  console.log('Seeding...');\n  // Create tags first\n  const tags = await Promise.all(['javascript','nodejs','react','typescript','express'].map(name =>\n    p.tag.upsert({ where: { name }, create: { name }, update: {} })\n  ));\n  // Create users with posts\n  for (let i = 1; i <= 10; i++) {\n    const user = await p.user.upsert({\n      where: { email: `user${i}@example.com` },\n      create: { name: `User ${i}`, email: `user${i}@example.com`, role: i===1?'admin':'user' },\n      update: {}\n    });\n    for (let j = 1; j <= 3; j++) {\n      const post = await p.post.create({\n        data: {\n          title: `Post ${j} by User ${i}`,\n          body: `Content of post ${j} by user ${i}. `.repeat(10),\n          authorId: user.id,\n          published: Math.random() > 0.2,\n          tags: { connect: tags.slice(0, Math.ceil(Math.random()*3)).map(t=>({id:t.id})) }\n        }\n      });\n      for (let k = 1; k <= 5; k++) {\n        await p.comment.create({ data: { body: `Comment ${k} on post ${j}`, postId: post.id, authorId: user.id } });\n      }\n    }\n  }\n  console.log('Done!');\n}\nseed().catch(console.error).finally(()=>p.$disconnect());",hints:"upsert for idempotent seeding. connect existing tags by ID. Create in dependency order: tags -> users -> posts -> comments.",solutionExplanation:"Idempotent seed: upsert instead of create prevents duplicate seed errors. connect for many-to-many (posts-tags). Dependency order ensures FK constraints."},
  {lessonId:51,difficulty:"Medium",title:"Prisma Pagination Patterns",problemStatement:"Implement three pagination patterns with Prisma: offset/limit, cursor-based, and keyset. Compare performance for each.",examples:"offsetPage(2,10) -> skip:10. cursorPage(lastId) -> cursor:{id:lastId}. keysetPage(lastDate,lastId) -> where:{createdAt:{lte}}",starterCodeJs:"async function paginationPatterns(p) {\n  // 1. Offset pagination (simple but slow for deep pages)\n  async function offsetPage(page, limit) {\n    const [data, total] = await p.$transaction([\n      p.post.findMany({ skip: (page-1)*limit, take: limit, orderBy: { createdAt: 'desc' } }),\n      p.post.count()\n    ]);\n    return { data, total, page, pages: Math.ceil(total/limit) };\n  }\n  // 2. Cursor pagination (Prisma native, stable)\n  async function cursorPage(cursor, limit = 10) {\n    const data = await p.post.findMany({\n      take: limit,\n      skip: cursor ? 1 : 0,\n      cursor: cursor ? { id: cursor } : undefined,\n      orderBy: { id: 'desc' }\n    });\n    return { data, nextCursor: data[data.length-1]?.id, hasMore: data.length === limit };\n  }\n  // 3. Keyset (most scalable - no cursor offset)\n  async function keysetPage(afterDate, afterId, limit = 10) {\n    const data = await p.post.findMany({\n      where: afterDate ? { OR: [{ createdAt: { lt: afterDate } }, { createdAt: afterDate, id: { lt: afterId } }] } : undefined,\n      orderBy: [{ createdAt: 'desc' }, { id: 'desc' }],\n      take: limit\n    });\n    return { data, hasMore: data.length === limit };\n  }\n  return { offsetPage, cursorPage, keysetPage };\n}",hints:"Cursor: skip:1 skips the cursor row itself. Keyset: OR condition handles same-timestamp tie-breaking. Offset gets slower on large datasets.",solutionExplanation:"Offset: O(offset) - slow for deep pages. Cursor: stable but index-dependent. Keyset: most efficient, uses index for WHERE instead of SKIP."},
  {lessonId:51,difficulty:"Easy",title:"Prisma Aggregations",problemStatement:"Use Prisma's aggregate functions: count, sum, avg, min, max, groupBy. Calculate statistics from a posts dataset.",examples:"p.post.aggregate({_count:true, _avg:{views:true}}). p.post.groupBy({by:['authorId'], _count:{id:true}})",starterCodeJs:"async function aggregations(p) {\n  // Basic aggregation\n  const stats = await p.post.aggregate({\n    _count: { id: true },\n    _avg: { views: true },\n    _max: { views: true },\n    _min: { views: true },\n    _sum: { views: true },\n    where: { published: true }\n  });\n  // Group by author\n  const byAuthor = await p.post.groupBy({\n    by: ['authorId'],\n    _count: { id: true },\n    _avg: { views: true },\n    orderBy: { _count: { id: 'desc' } },\n    take: 10\n  });\n  // Group by date (truncated)\n  const byMonth = await p.$queryRaw`\n    SELECT strftime('%Y-%m', created_at) as month, COUNT(*) as count\n    FROM posts GROUP BY month ORDER BY month DESC LIMIT 12\n  `;\n  return { stats, byAuthor, byMonth };\n}",hints:"aggregate() computes multiple stats in one query. groupBy() with _count, _avg etc. having() filters groups (like WHERE for aggregations).",solutionExplanation:"Prisma aggregations: aggregate() for overall stats, groupBy() for per-group stats. Raw SQL needed for date truncation (strftime, DATE_TRUNC vary by DB)."},
  {lessonId:51,difficulty:"Hard",title:"Prisma Schema Design",problemStatement:"Design a Prisma schema for a social media app with users, posts, comments, likes, follows, and notifications. Include proper indexes and relations.",examples:"User follows User (self-relation). Post has likes. Notification polymorphism via target type.",starterCodeJs:"// schema.prisma\nconst schema = `\nmodel User {\n  id           Int       @id @default(autoincrement())\n  name         String\n  email        String    @unique\n  passwordHash String?   @map('password_hash')\n  avatar       String?\n  bio          String?   @db.Text\n  role         Role      @default(USER)\n  createdAt    DateTime  @default(now()) @map('created_at')\n  posts        Post[]    @relation('AuthorPosts')\n  comments     Comment[]\n  likes        Like[]\n  following    Follow[]  @relation('Following')\n  followers    Follow[]  @relation('Followers')\n  notifications Notification[]\n  @@map('users')\n}\nmodel Follow {\n  followerId  Int  @map('follower_id')\n  followingId Int  @map('following_id')\n  createdAt   DateTime @default(now()) @map('created_at')\n  follower    User @relation('Following', fields:[followerId], references:[id], onDelete:Cascade)\n  following   User @relation('Followers', fields:[followingId], references:[id], onDelete:Cascade)\n  @@id([followerId, followingId])\n  @@map('follows')\n}\nmodel Like {\n  userId    Int  @map('user_id')\n  postId    Int  @map('post_id')\n  createdAt DateTime @default(now()) @map('created_at')\n  user User @relation(fields:[userId], references:[id], onDelete:Cascade)\n  post Post @relation(fields:[postId], references:[id], onDelete:Cascade)\n  @@id([userId, postId])\n  @@map('likes')\n}\n`;\nconsole.log(schema);",hints:"Self-relation on User for follows needs two named @relation decorators. Composite @@id for junction tables. onDelete:Cascade for likes/follows when user/post deleted.",solutionExplanation:"Self-relation follow: one User has two relations to User (as follower, as following). Composite PK on junction table prevents duplicate follows. Named relations disambiguate."},

  // Lesson 52 - Database Design coding
  {lessonId:52,difficulty:"Easy",title:"ER Diagram to Schema",problemStatement:"Given an ER diagram for a library system, write the SQL CREATE TABLE statements. Library has Books, Members, Loans, and Authors.",examples:"Books(id,title,isbn,authorId). Loans(memberId,bookId,dueDate). Many books per author.",starterCodeJs:"const librarySchema = `\nCREATE TABLE authors (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  name TEXT NOT NULL,\n  email TEXT UNIQUE,\n  bio TEXT,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\nCREATE TABLE books (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  title TEXT NOT NULL,\n  isbn TEXT UNIQUE NOT NULL,\n  author_id INTEGER REFERENCES authors(id) ON DELETE SET NULL,\n  published_year INTEGER,\n  genre TEXT,\n  copies_total INTEGER DEFAULT 1,\n  copies_available INTEGER DEFAULT 1,\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\nCREATE TABLE members (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  name TEXT NOT NULL,\n  email TEXT UNIQUE NOT NULL,\n  phone TEXT,\n  joined_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  active BOOLEAN DEFAULT 1\n);\nCREATE TABLE loans (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  book_id INTEGER NOT NULL REFERENCES books(id),\n  member_id INTEGER NOT NULL REFERENCES members(id),\n  loaned_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  due_date DATETIME NOT NULL,\n  returned_at DATETIME\n);\nCREATE INDEX idx_loans_member ON loans(member_id);\nCREATE INDEX idx_loans_book ON loans(book_id);\nCREATE INDEX idx_loans_due ON loans(due_date) WHERE returned_at IS NULL;\n`;",hints:"copies_available for tracking availability without complex queries. Partial index on due_date WHERE not returned is efficient. ON DELETE SET NULL for author deletion.",solutionExplanation:"Denormalized copies_available: updated on loan/return, avoids counting active loans every time. Partial index: only un-returned loans need due date indexing."},
  {lessonId:52,difficulty:"Medium",title:"Normalization Exercise",problemStatement:"Take a denormalized orders table and normalize it to 3NF. Show the original table, identify anomalies, and produce the normalized design.",examples:"Orders(orderId, custName, custEmail, prodName, prodPrice, qty) -> separate Customer, Product, Order, OrderItem tables.",starterCodeJs:"// BEFORE normalization (violates 1NF-3NF)\n// order_id | cust_name | cust_email | prod_name | prod_price | qty | total\n// 1        | Alice     | a@b.com    | Book      | 12.99      | 2   | 25.98\n// Problems: repeated cust data, repeated prod data, derived total\n// AFTER: 3NF\nconst normalizedSchema = `\nCREATE TABLE customers (\n  id INTEGER PRIMARY KEY,\n  name TEXT NOT NULL,\n  email TEXT UNIQUE NOT NULL\n);\nCREATE TABLE products (\n  id INTEGER PRIMARY KEY,\n  name TEXT NOT NULL,\n  price DECIMAL(10,2) NOT NULL\n);\nCREATE TABLE orders (\n  id INTEGER PRIMARY KEY,\n  customer_id INTEGER REFERENCES customers(id),\n  ordered_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  status TEXT DEFAULT 'pending'\n);\nCREATE TABLE order_items (\n  order_id INTEGER REFERENCES orders(id),\n  product_id INTEGER REFERENCES products(id),\n  quantity INTEGER NOT NULL,\n  price_at_time DECIMAL(10,2) NOT NULL, -- snapshot price\n  PRIMARY KEY (order_id, product_id)\n);\n`;\n// price_at_time = denormalization for price history accuracy",hints:"price_at_time: intentional denormalization - product price changes, but order price should be fixed at purchase time. Total is derived (qty*price) not stored.",solutionExplanation:"3NF: no transitive dependencies. Price history: store price_at_time on order_item (correct denormalization). Total is computed on read (not stored)."},
  {lessonId:52,difficulty:"Medium",title:"Database Constraint Design",problemStatement:"Add database constraints to prevent invalid data: check constraints, unique combinations, foreign key cascades, and triggers.",examples:"Account balance cannot go negative. User can only follow themselves would be rejected by check constraint.",starterCodeJs:"const constrainedSchema = `\n-- Check constraints\nCREATE TABLE accounts (\n  id INTEGER PRIMARY KEY,\n  user_id INTEGER REFERENCES users(id),\n  balance DECIMAL(15,2) DEFAULT 0 CHECK(balance >= 0),\n  account_type TEXT CHECK(account_type IN ('checking','savings','credit'))\n);\n-- Unique combination\nCREATE TABLE course_enrollments (\n  student_id INTEGER REFERENCES students(id),\n  course_id INTEGER REFERENCES courses(id),\n  enrolled_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  grade TEXT CHECK(grade IN ('A','B','C','D','F') OR grade IS NULL),\n  UNIQUE(student_id, course_id) -- no duplicate enrollment\n);\n-- Self-reference prevention via trigger\nCREATE TABLE follows (\n  follower_id INTEGER,\n  following_id INTEGER,\n  CHECK(follower_id != following_id), -- can't follow yourself\n  PRIMARY KEY(follower_id, following_id)\n);\n-- Cascade delete\nCREATE TABLE posts (\n  id INTEGER PRIMARY KEY,\n  author_id INTEGER REFERENCES users(id) ON DELETE CASCADE\n);\n`;",hints:"CHECK constraints validate column values at insert/update. UNIQUE constraint on combinations. ON DELETE CASCADE removes child rows when parent deleted.",solutionExplanation:"DB constraints are last line of defense (app should validate too). CHECK for valid values. UNIQUE for combinations. CASCADE for referential integrity maintenance."},
  {lessonId:52,difficulty:"Hard",title:"Recursive CTE for Tree Data",problemStatement:"Store and query a hierarchical category tree using recursive CTEs. Support: get all descendants, get ancestors path, depth-limited queries.",examples:"SELECT * FROM categories WITH subtree AS (recursive CTE) to get all children of a category.",starterCodeJs:"// Schema for adjacency list (simpler but requires recursive query)\nconst treeSchema = `\nCREATE TABLE categories (\n  id INTEGER PRIMARY KEY,\n  name TEXT NOT NULL,\n  parent_id INTEGER REFERENCES categories(id) ON DELETE CASCADE,\n  sort_order INTEGER DEFAULT 0\n);\n`;\n// Recursive CTE to get all descendants\nconst getDescendants = (rootId) => `\nWITH RECURSIVE subtree AS (\n  SELECT id, name, parent_id, 0 as depth\n  FROM categories WHERE id = ${rootId}\n  UNION ALL\n  SELECT c.id, c.name, c.parent_id, st.depth + 1\n  FROM categories c\n  JOIN subtree st ON c.parent_id = st.id\n)\nSELECT * FROM subtree ORDER BY depth, sort_order\n`;\n// Get ancestor path (breadcrumb)\nconst getAncestors = (categoryId) => `\nWITH RECURSIVE ancestors AS (\n  SELECT id, name, parent_id, 0 as level\n  FROM categories WHERE id = ${categoryId}\n  UNION ALL\n  SELECT c.id, c.name, c.parent_id, a.level + 1\n  FROM categories c\n  JOIN ancestors a ON c.id = a.parent_id\n)\nSELECT * FROM ancestors ORDER BY level DESC\n`;",hints:"Recursive CTE: base case selects root, recursive case joins on parent_id. depth/level tracks distance from root. ORDER BY depth for BFS order.",solutionExplanation:"Adjacency list + recursive CTE: simple schema, powerful queries. Alternative: nested sets (complex writes, fast reads) or path enumeration (easy reads, hard moves)."},
  {lessonId:52,difficulty:"Easy",title:"Soft Delete Pattern",problemStatement:"Implement soft delete with a deleted_at column. Write queries that automatically exclude soft-deleted records and allow restore.",examples:"DELETE becomes UPDATE SET deleted_at=now(). All SELECTs automatically add WHERE deleted_at IS NULL.",starterCodeJs:"// Schema\nconst schema = `\nALTER TABLE posts ADD COLUMN deleted_at DATETIME;\nCREATE INDEX idx_posts_deleted ON posts(deleted_at) WHERE deleted_at IS NULL;\n`;\n// Application functions\nasync function softDelete(db, table, id) {\n  return db.run(`UPDATE ${table} SET deleted_at = CURRENT_TIMESTAMP WHERE id = ?`, id);\n}\nasync function restore(db, table, id) {\n  return db.run(`UPDATE ${table} SET deleted_at = NULL WHERE id = ?`, id);\n}\nasync function findActive(db, table, where = '1=1', params = []) {\n  return db.all(`SELECT * FROM ${table} WHERE deleted_at IS NULL AND (${where})`, params);\n}\nasync function findWithDeleted(db, table) {\n  return db.all(`SELECT *, deleted_at IS NOT NULL as is_deleted FROM ${table}`);\n}\nasync function hardDeleteOld(db, table, daysOld = 30) {\n  return db.run(`DELETE FROM ${table} WHERE deleted_at < datetime('now', '-${daysOld} days')`);\n}",hints:"Partial index on deleted_at WHERE NULL makes active-record queries fast. hardDeleteOld for GDPR compliance (permanent removal after retention period).",solutionExplanation:"Soft delete: mark as deleted, keep data. Partial index on active records (deleted_at IS NULL) keeps queries fast. Periodic hard delete for GDPR/storage."},
  {lessonId:52,difficulty:"Hard",title:"Multi-tenant Database Design",problemStatement:"Design a multi-tenant schema with row-level tenant isolation. All tables have tenant_id. Enforce tenant isolation in application layer.",examples:"Every SELECT has WHERE tenant_id = currentTenant. CREATE TABLE posts has tenant_id NOT NULL REFERENCES tenants(id).",starterCodeJs:"const multiTenantSchema = `\nCREATE TABLE tenants (\n  id INTEGER PRIMARY KEY,\n  name TEXT NOT NULL,\n  slug TEXT UNIQUE NOT NULL,\n  plan TEXT DEFAULT 'free',\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP\n);\nCREATE TABLE users (\n  id INTEGER PRIMARY KEY,\n  tenant_id INTEGER NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,\n  email TEXT NOT NULL,\n  UNIQUE(tenant_id, email) -- email unique within tenant\n);\nCREATE TABLE posts (\n  id INTEGER PRIMARY KEY,\n  tenant_id INTEGER NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,\n  author_id INTEGER NOT NULL REFERENCES users(id),\n  title TEXT NOT NULL\n);\nCREATE INDEX idx_users_tenant ON users(tenant_id);\nCREATE INDEX idx_posts_tenant ON posts(tenant_id);\n`;\n// Tenant-aware DB wrapper\nclass TenantDB {\n  constructor(db, tenantId) { this._db = db; this._tenantId = tenantId; }\n  async findPosts(where='') {\n    return this._db.all(`SELECT * FROM posts WHERE tenant_id=? ${where?'AND '+where:''}`, this._tenantId);\n  }\n  async createPost(data) {\n    return this._db.run('INSERT INTO posts (tenant_id,author_id,title) VALUES (?,?,?)', this._tenantId, data.authorId, data.title);\n  }\n}",hints:"tenant_id on every table. TenantDB wrapper always injects tenant_id. Unique email per tenant not globally. CASCADE delete for tenant cleanup.",solutionExplanation:"Row-level tenancy: tenant_id column on all tables. Wrapper class injects tenant_id automatically preventing cross-tenant data leaks. Email unique within tenant."},
  {lessonId:52,difficulty:"Medium",title:"Database Denormalization Strategy",problemStatement:"Demonstrate strategic denormalization: add post_count to users table. Show update triggers and eventual consistency approaches.",examples:"users.post_count is updated via trigger on post INSERT/DELETE. Avoids COUNT query every time.",starterCodeJs:"// Schema with denormalized counter\nconst denormSchema = `\nALTER TABLE users ADD COLUMN post_count INTEGER DEFAULT 0;\nALTER TABLE users ADD COLUMN follower_count INTEGER DEFAULT 0;\n-- Trigger to maintain post_count\nCREATE TRIGGER after_post_insert\nAFTER INSERT ON posts\nBEGIN\n  UPDATE users SET post_count = post_count + 1 WHERE id = NEW.author_id;\nEND;\nCREATE TRIGGER after_post_delete\nAFTER DELETE ON posts\nBEGIN\n  UPDATE users SET post_count = post_count - 1 WHERE id = OLD.author_id;\nEND;\n`;\n// Periodic recalculation to fix drift\nasync function recalculateCounters(db) {\n  await db.run(`\n    UPDATE users SET post_count = (\n      SELECT COUNT(*) FROM posts WHERE author_id = users.id AND deleted_at IS NULL\n    )\n  `);\n  console.log('Counters recalculated');\n}",hints:"Triggers maintain counter automatically. Periodic recalculation fixes drift from bugs. Denormalized counters: O(1) reads vs O(n) COUNT queries.",solutionExplanation:"Denormalized counters: fast reads (no JOIN+COUNT). Triggers maintain consistency on insert/delete. Periodic recalculate handles edge cases and resets drift."},
  {lessonId:52,difficulty:"Easy",title:"Database Views for Reports",problemStatement:"Create database views for common report queries: user_stats view, active_posts view, and monthly_summary view.",examples:"CREATE VIEW user_stats AS SELECT users.*, COUNT(posts.id) as post_count... SELECT * FROM user_stats WHERE post_count > 5.",starterCodeJs:"const views = `\n-- User statistics view\nCREATE VIEW user_stats AS\nSELECT\n  u.id, u.name, u.email, u.role, u.created_at,\n  COUNT(DISTINCT p.id) as post_count,\n  COUNT(DISTINCT c.id) as comment_count,\n  COALESCE(SUM(p.views), 0) as total_views\nFROM users u\nLEFT JOIN posts p ON p.author_id = u.id AND p.deleted_at IS NULL\nLEFT JOIN comments c ON c.author_id = u.id\nGROUP BY u.id;\n-- Active posts with author info\nCREATE VIEW active_posts AS\nSELECT\n  p.*, u.name as author_name, u.avatar as author_avatar,\n  COUNT(c.id) as comment_count\nFROM posts p\nJOIN users u ON u.id = p.author_id\nLEFT JOIN comments c ON c.post_id = p.id\nWHERE p.published = 1 AND p.deleted_at IS NULL\nGROUP BY p.id;\n-- Monthly post summary\nCREATE VIEW monthly_summary AS\nSELECT strftime('%Y-%m', created_at) as month, COUNT(*) as posts, SUM(views) as total_views\nFROM posts WHERE published=1 GROUP BY month ORDER BY month DESC;\n`;",hints:"Views are saved queries. SELECT * FROM user_stats works like a table. COALESCE handles NULL from LEFT JOIN. COUNT(DISTINCT) prevents duplicate counting from multiple joins.",solutionExplanation:"Views simplify complex queries. user_stats: multiple LEFT JOINs need COUNT(DISTINCT) to avoid duplicates. Views can be queried with WHERE, ORDER BY, LIMIT."},
  {lessonId:52,difficulty:"Hard",title:"Event Sourcing Pattern",problemStatement:"Implement event sourcing: store all changes as events, derive current state by replaying events. Build for a bank account.",examples:"AccountOpened, MoneyDeposited, MoneyWithdrawn events. Current balance = sum of all transactions.",starterCodeJs:"const schema = `\nCREATE TABLE account_events (\n  id INTEGER PRIMARY KEY AUTOINCREMENT,\n  account_id TEXT NOT NULL,\n  type TEXT NOT NULL CHECK(type IN ('AccountOpened','Deposited','Withdrawn','Closed')),\n  amount DECIMAL(15,2),\n  metadata TEXT, -- JSON\n  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,\n  created_by INTEGER REFERENCES users(id)\n);\nCREATE INDEX idx_events_account ON account_events(account_id, created_at);\n`;\nasync function appendEvent(db, accountId, type, amount, metadata={}) {\n  return db.run('INSERT INTO account_events (account_id,type,amount,metadata) VALUES (?,?,?,?)',\n    accountId, type, amount, JSON.stringify(metadata));\n}\nasync function getBalance(db, accountId) {\n  const events = await db.all('SELECT type, amount FROM account_events WHERE account_id=? ORDER BY id', accountId);\n  return events.reduce((balance, e) => {\n    if (e.type==='Deposited') return balance + e.amount;\n    if (e.type==='Withdrawn') return balance - e.amount;\n    return balance;\n  }, 0);\n}\nasync function getHistory(db, accountId) {\n  return db.all('SELECT * FROM account_events WHERE account_id=? ORDER BY id', accountId);\n}",hints:"Events are immutable and append-only. State = replay of all events. Snapshot optimization for long histories (store periodic balance). Audit log is free.",solutionExplanation:"Event sourcing: never UPDATE/DELETE, only INSERT events. Current state derived by replay. Benefits: full audit trail, time travel, event-driven integration."},

  // Lesson 53 - DB Performance coding
  {lessonId:53,difficulty:"Easy",title:"Query Performance Analysis",problemStatement:"Write a function that runs EXPLAIN ANALYZE on a query and parses the output to identify if indexes are used and estimate performance.",examples:"analyzeQuery(db, sql, params) returns {usesIndex:true, scanType:'SEARCH', estimatedRows:50}",starterCodeJs:"async function analyzeQuery(db, sql, params=[]) {\n  const plan = await db.all(`EXPLAIN QUERY PLAN ${sql}`, params);\n  const details = plan.map(row => row.detail || row.detail);\n  const usesIndex = details.some(d => d&&(d.includes('USING INDEX')||d.includes('SEARCH TABLE')));\n  const fullScan = details.some(d => d&&d.includes('SCAN TABLE'));\n  return {\n    usesIndex,\n    fullScan,\n    plan: details,\n    recommendation: fullScan && !usesIndex ? 'Consider adding an index' : 'Query plan looks good'\n  };\n}\nasync function benchmarkQuery(db, sql, params=[], iterations=100) {\n  const times = [];\n  for (let i=0; i<iterations; i++) {\n    const t = Date.now();\n    await db.all(sql, params);\n    times.push(Date.now()-t);\n  }\n  times.sort((a,b)=>a-b);\n  return {\n    min: times[0],\n    max: times[times.length-1],\n    avg: (times.reduce((a,b)=>a+b,0)/times.length).toFixed(2),\n    p95: times[Math.floor(times.length*0.95)]\n  };\n}",hints:"EXPLAIN QUERY PLAN returns rows with detail string. SCAN TABLE = full scan. SEARCH TABLE = index used. Run multiple iterations for stable benchmark.",solutionExplanation:"EXPLAIN QUERY PLAN: identifies access method. SCAN = O(n) full table scan. SEARCH with index = O(log n). Benchmark with multiple iterations for stable p95."},
  {lessonId:53,difficulty:"Medium",title:"Index Coverage Analysis",problemStatement:"Analyze which indexes are needed for a set of common queries. Create indexes and verify they improve query plans.",examples:"Query: WHERE email=? AND status='active' needs composite index on (email,status).",starterCodeJs:"async function optimizeIndexes(db) {\n  // Common query patterns to optimize:\n  const queries = [\n    { sql: 'SELECT * FROM users WHERE email=?', reason: 'login lookup' },\n    { sql: 'SELECT * FROM posts WHERE author_id=? AND published=1 ORDER BY created_at DESC LIMIT 10', reason: 'user post list' },\n    { sql: 'SELECT * FROM comments WHERE post_id=? ORDER BY created_at ASC', reason: 'post comments' },\n    { sql: 'SELECT * FROM users WHERE role=? AND created_at > ?', reason: 'admin user list' }\n  ];\n  // Create strategic indexes\n  const indexes = [\n    'CREATE INDEX IF NOT EXISTS idx_users_email ON users(email)',\n    'CREATE INDEX IF NOT EXISTS idx_posts_author_published ON posts(author_id, published, created_at DESC)',\n    'CREATE INDEX IF NOT EXISTS idx_comments_post ON comments(post_id, created_at ASC)',\n    'CREATE INDEX IF NOT EXISTS idx_users_role_created ON users(role, created_at)'\n  ];\n  for (const sql of indexes) await db.run(sql);\n  // Verify with EXPLAIN\n  for (const q of queries) {\n    const plan = await db.all(`EXPLAIN QUERY PLAN ${q.sql}`);\n    console.log(q.reason, ':', plan.map(r=>r.detail));\n  }\n}",hints:"Composite index column order: put equality conditions first, then range, then sort. DESC in index matches ORDER BY DESC without sort step.",solutionExplanation:"Index for (author_id, published, created_at): first two are equality, last is ORDER BY. DB uses index for WHERE + ORDER BY avoiding separate sort."},
  {lessonId:53,difficulty:"Medium",title:"Connection Pool Monitoring",problemStatement:"Build a monitored connection pool that tracks: active connections, wait time, pool exhaustion events, and query times.",examples:"pool.getStats() -> {active:5,idle:5,waiting:2,avgQueryMs:12,totalQueries:1000}",starterCodeJs:"class MonitoredPool {\n  constructor(pool, options={}) {\n    this._pool = pool;\n    this._stats = { active:0, idle:0, waiting:0, totalQueries:0, totalMs:0, exhaustions:0 };\n    this._waitTimes = [];\n    this._queryTimes = [];\n  }\n  async acquire() {\n    const waitStart = Date.now();\n    if (this._stats.idle === 0 && this._stats.active >= this._pool.max) this._stats.exhaustions++;\n    this._stats.waiting++;\n    try {\n      const conn = await this._pool.acquire();\n      const waited = Date.now() - waitStart;\n      this._waitTimes.push(waited);\n      if (this._waitTimes.length > 1000) this._waitTimes.shift();\n      this._stats.waiting--;\n      this._stats.active++;\n      return conn;\n    } catch(err) { this._stats.waiting--; throw err; }\n  }\n  release(conn) { this._stats.active--; this._stats.idle++; this._pool.release(conn); }\n  async query(fn) {\n    const conn = await this.acquire();\n    const t = Date.now();\n    try {\n      const result = await fn(conn);\n      const ms = Date.now()-t;\n      this._stats.totalQueries++;\n      this._stats.totalMs += ms;\n      this._queryTimes.push(ms);\n      if (this._queryTimes.length > 1000) this._queryTimes.shift();\n      return result;\n    } finally { this.release(conn); }\n  }\n  getStats() {\n    const qt = [...this._queryTimes].sort((a,b)=>a-b);\n    return { ...this._stats, avgQueryMs: this._stats.totalMs/(this._stats.totalQueries||1)|0, p95QueryMs: qt[Math.floor(qt.length*.95)]||0 };\n  }\n}",hints:"Wrap pool.acquire/release to track counts. query() helper acquires, runs fn, releases in finally. Rolling window for percentiles.",solutionExplanation:"Monitoring wrapper: track active/idle/waiting counts. p95 query time reveals slow queries. exhaustions count reveals pool undersizing."},
  {lessonId:53,difficulty:"Hard",title:"N+1 Query Detector",problemStatement:"Build a middleware/wrapper that detects N+1 query patterns: when the same query runs N times inside a request with different IDs.",examples:"Detects: SELECT * FROM users WHERE id=1, then id=2, then id=3... 'N+1 detected: 50 similar queries'",starterCodeJs:"class N1Detector {\n  constructor(threshold=5) {\n    this._threshold = threshold;\n    this._queryPatterns = new Map();\n  }\n  track(sql, params=[]) {\n    // Normalize query (replace literal values with ?)\n    const pattern = sql.replace(/=\\s*\\d+/g,'=?').replace(/IN\\s*\\([^)]+\\)/g,'IN (?)').trim();\n    if (!this._queryPatterns.has(pattern)) this._queryPatterns.set(pattern, { count:0, examples:[] });\n    const entry = this._queryPatterns.get(pattern);\n    entry.count++;\n    if (entry.examples.length < 3) entry.examples.push({ sql, params });\n    if (entry.count === this._threshold) {\n      console.warn(`[N+1 DETECTED] Query ran ${entry.count}+ times:\\n${pattern}\\nExample: ${sql}`);\n    }\n  }\n  getReport() {\n    const issues = [];\n    for (const [pattern, data] of this._queryPatterns) {\n      if (data.count >= this._threshold) issues.push({ pattern, count: data.count, examples: data.examples });\n    }\n    return issues.sort((a,b)=>b.count-a.count);\n  }\n  reset() { this._queryPatterns.clear(); }\n}",hints:"Normalize SQL by replacing literal IDs with placeholders to identify the pattern. Warn at threshold. Report shows all N+1 candidates.",solutionExplanation:"N+1 detection: normalize queries to find pattern repetition. 50 queries with pattern 'WHERE id=?' = N+1. Fix: collect IDs, use WHERE id IN (?,...)."},
  {lessonId:53,difficulty:"Hard",title:"Query Result Cache with Invalidation",problemStatement:"Build a query cache that stores results, invalidates by table name when writes occur, and supports cache warming.",examples:"cache.query('SELECT * FROM users') caches result. cache.invalidate('users') clears all user queries.",starterCodeJs:"class QueryCache {\n  constructor({ ttl=60, maxSize=500 } = {}) {\n    this._cache = new Map();\n    this._tableMap = new Map(); // table -> Set<cacheKeys>\n    this._ttl = ttl * 1000;\n    this._maxSize = maxSize;\n  }\n  _extractTables(sql) {\n    const matches = sql.toLowerCase().match(/(?:from|join)\\s+([a-z_]+)/g) || [];\n    return matches.map(m => m.replace(/(?:from|join)\\s+/, ''));\n  }\n  async query(sql, params=[], db) {\n    const key = sql + JSON.stringify(params);\n    const cached = this._cache.get(key);\n    if (cached && Date.now() < cached.exp) return cached.data;\n    const data = await db.all(sql, params);\n    if (this._cache.size >= this._maxSize) this._evictOldest();\n    const tables = this._extractTables(sql);\n    this._cache.set(key, { data, exp: Date.now()+this._ttl, tables, accessedAt: Date.now() });\n    tables.forEach(t => { if (!this._tableMap.has(t)) this._tableMap.set(t, new Set()); this._tableMap.get(t).add(key); });\n    return data;\n  }\n  invalidate(...tables) {\n    tables.forEach(table => {\n      const keys = this._tableMap.get(table) || new Set();\n      keys.forEach(k => this._cache.delete(k));\n      this._tableMap.delete(table);\n    });\n  }\n  _evictOldest() {\n    const oldest = [...this._cache.entries()].sort((a,b)=>a[1].accessedAt-b[1].accessedAt)[0];\n    if (oldest) this._cache.delete(oldest[0]);\n  }\n}",hints:"Extract table names from SQL with regex on FROM/JOIN keywords. Map table -> cache keys for targeted invalidation. LRU eviction on max size.",solutionExplanation:"Query cache with table tracking: invalidate all queries touching a table when that table changes. Regex-based table extraction from SQL. LRU for bounded memory."},
  {lessonId:53,difficulty:"Medium",title:"Database Benchmarking Suite",problemStatement:"Build a benchmarking suite that measures INSERT throughput, SELECT latency (indexed vs non-indexed), and JOIN performance.",examples:"benchmark.run() returns {insertPerSecond:5000, indexedSelectMs:0.5, fullScanMs:45, joinMs:12}",starterCodeJs:"async function benchmarkDatabase(db) {\n  const results = {};\n  // Setup: create test tables\n  await db.run('CREATE TABLE IF NOT EXISTS bench_users (id INTEGER PRIMARY KEY, name TEXT, email TEXT, age INTEGER)');\n  await db.run('CREATE TABLE IF NOT EXISTS bench_posts (id INTEGER PRIMARY KEY, user_id INTEGER, title TEXT)');\n  // 1. INSERT throughput\n  const insertCount = 1000;\n  const t1 = Date.now();\n  const stmt = await db.prepare('INSERT INTO bench_users (name,email,age) VALUES (?,?,?)');\n  for (let i=0; i<insertCount; i++) await stmt.run(`User${i}`,`user${i}@test.com`, 20+i%50);\n  results.insertPerSecond = Math.round(insertCount / ((Date.now()-t1)/1000));\n  // 2. Full scan vs indexed\n  const t2 = Date.now();\n  for (let i=0; i<100; i++) await db.get('SELECT * FROM bench_users WHERE age=?', 30);\n  results.fullScanAvgMs = ((Date.now()-t2)/100).toFixed(2);\n  await db.run('CREATE INDEX IF NOT EXISTS idx_bench_age ON bench_users(age)');\n  const t3 = Date.now();\n  for (let i=0; i<100; i++) await db.get('SELECT * FROM bench_users WHERE age=?', 30);\n  results.indexedAvgMs = ((Date.now()-t3)/100).toFixed(2);\n  // Cleanup\n  await db.run('DROP TABLE bench_users');\n  await db.run('DROP TABLE bench_posts');\n  return results;\n}",hints:"Warm up with a few queries before benchmarking. Multiple iterations for stable average. Compare same query before/after index creation.",solutionExplanation:"Benchmarking: INSERT throughput reveals write performance. Full scan vs indexed SELECT shows index impact. Always use multiple iterations for stable results."},
  {lessonId:53,difficulty:"Easy",title:"Slow Query Logger",problemStatement:"Wrap database queries with a logger that records queries taking over a threshold time. Expose slowest queries report.",examples:"slowQueries(50) logs any query taking >50ms. getReport() shows top 10 slowest.",starterCodeJs:"class SlowQueryLogger {\n  constructor(db, thresholdMs=50) {\n    this._db = db;\n    this._threshold = thresholdMs;\n    this._log = [];\n  }\n  async run(sql, params=[]) {\n    const t = Date.now();\n    const result = await this._db.run(sql, params);\n    const ms = Date.now()-t;\n    if (ms >= this._threshold) {\n      this._log.push({ sql, params, ms, time: new Date().toISOString() });\n      console.warn(`[SLOW QUERY ${ms}ms] ${sql}`);\n    }\n    return result;\n  }\n  async all(sql, params=[]) {\n    const t = Date.now();\n    const rows = await this._db.all(sql, params);\n    const ms = Date.now()-t;\n    if (ms >= this._threshold) this._log.push({ sql, params, ms, rows: rows.length, time: new Date().toISOString() });\n    return rows;\n  }\n  getReport(top=10) {\n    return [...this._log].sort((a,b)=>b.ms-a.ms).slice(0, top);\n  }\n  clearLog() { this._log = []; }\n  setThreshold(ms) { this._threshold = ms; }\n}",hints:"Wrap each DB method with timing. Only log when over threshold. Report sorted by ms descending shows worst offenders.",solutionExplanation:"Slow query logger: timing wrapper pattern. Log slow queries for later analysis. getReport() shows queries needing optimization. Proxy pattern wraps all methods."},
  {lessonId:53,difficulty:"Hard",title:"Read Replica Router",problemStatement:"Build a database router that sends writes to primary and reads to replicas. Support multiple replicas with round-robin load balancing.",examples:"router.query() uses replica. router.execute() uses primary. Automatic failover to primary if replica down.",starterCodeJs:"class ReplicaRouter {\n  constructor(primary, replicas=[]) {\n    this._primary = primary;\n    this._replicas = replicas;\n    this._rr = 0; // round-robin index\n    this._health = new Map(replicas.map(r=>[r,true]));\n  }\n  _getReadDB() {\n    const healthy = this._replicas.filter(r => this._health.get(r));\n    if (!healthy.length) return this._primary; // fallback to primary\n    const db = healthy[this._rr % healthy.length];\n    this._rr++;\n    return db;\n  }\n  async query(sql, params=[]) {\n    const db = this._getReadDB();\n    try { return await db.all(sql, params); }\n    catch(err) { this._health.set(db, false); setTimeout(()=>this._health.set(db,true), 30000); return this._primary.all(sql, params); }\n  }\n  async execute(sql, params=[]) {\n    return this._primary.run(sql, params); // always primary for writes\n  }\n  async transaction(fn) {\n    return fn(this._primary); // transactions always on primary\n  }\n  getHealth() { return Object.fromEntries(this._health); }\n}",hints:"Round-robin: increment counter mod healthy replicas count. Mark unhealthy on error, auto-recover after 30s. Writes/transactions always to primary.",solutionExplanation:"Read/write splitting: writes need primary (consistency). Reads can use replicas (scaling). Health tracking with auto-recovery. Round-robin distributes read load."}
];

async function main() {
  let ci = 0, cs = 0;
  for (const q of codingQuestions) {
    const exists = await p.practiceQuestion.findFirst({ where: { lessonId: q.lessonId, title: q.title } });
    if (!exists) { await p.practiceQuestion.create({ data: q }); ci++; } else cs++;
  }
  console.log(`Coding: ${ci} inserted, ${cs} skipped.`);
}

main().catch(console.error).finally(() => p.$disconnect());
